For production systems, you need a centralized middleware approach that enforces method restrictions and authentication consistently across all endpoints. This prevents the scattered security logic that led to the GoAnywhere vulnerability.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"log"
	"net/http"
	"os"
	"strings"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promauto"
)

// Metrics for security monitoring
var (
	verbTamperingAttempts = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "http_verb_tampering_attempts_total",
			Help: "Count of HTTP verb tampering attempts",
		},
		[]string{"path", "method", "remote_ip"},
	)
	authFailures = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "auth_failures_total",
			Help: "Count of authentication failures",
		},
		[]string{"path", "remote_ip"},
	)
)

// RouteConfig defines allowed methods and auth requirements per route
type RouteConfig struct {
	AllowedMethods  []string
	RequiresAuth    bool
	RequiredRole    string
	RateLimitPerMin int
}

// SecurityMiddleware provides centralized security controls
type SecurityMiddleware struct {
	routes      map[string]RouteConfig
	authService *AuthService
	logger      *log.Logger
}

func NewSecurityMiddleware(authService *AuthService) *SecurityMiddleware {
	return &SecurityMiddleware{
		routes: map[string]RouteConfig{
			"/admin/user/delete": {
				AllowedMethods:  []string{"POST", "DELETE"},
				RequiresAuth:    true,
				RequiredRole:    "admin",
				RateLimitPerMin: 10,
			},
			"/admin/user/list": {
				AllowedMethods:  []string{"GET"},
				RequiresAuth:    true,
				RequiredRole:    "admin",
				RateLimitPerMin: 60,
			},
			"/api/health": {
				AllowedMethods:  []string{"GET", "HEAD"},
				RequiresAuth:    false,
				RateLimitPerMin: 120,
			},
		},
		authService: authService,
		logger:      log.New(os.Stdout, "[SECURITY] ", log.LstdFlags|log.Lshortfile),
	}
}

// Wrap applies all security controls to a handler
func (sm *SecurityMiddleware) Wrap(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		path := r.URL.Path
		method := strings.ToUpper(r.Method)
		remoteIP := getClientIP(r)

		// Layer 1: Route configuration lookup
		config, exists := sm.routes[path]
		if !exists {
			// Deny by default for unconfigured routes
			sm.logger.Printf("DENIED: Unconfigured route %s from %s", path, remoteIP)
			http.Error(w, "Not Found", http.StatusNotFound)
			return
		}

		// Layer 2: HTTP Method validation
		if !isMethodAllowed(method, config.AllowedMethods) {
			verbTamperingAttempts.WithLabelValues(path, method, remoteIP).Inc()
			sm.logger.Printf("VERB_TAMPERING: %s attempted %s on %s", remoteIP, method, path)

			// Return allowed methods in header for legitimate clients
			w.Header().Set("Allow", strings.Join(config.AllowedMethods, ", "))
			http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
			return
		}

		// Layer 3: Authentication check
		if config.RequiresAuth {
			user, err := sm.authenticateRequest(r)
			if err != nil {
				authFailures.WithLabelValues(path, remoteIP).Inc()
				sm.logger.Printf("AUTH_FAILED: %s on %s: %v", remoteIP, path, err)
				http.Error(w, "Unauthorized", http.StatusUnauthorized)
				return
			}

			// Layer 4: Role-based authorization
			if config.RequiredRole != "" && !user.HasRole(config.RequiredRole) {
				sm.logger.Printf("AUTHZ_DENIED: User %s lacks role %s for %s",
					user.ID, config.RequiredRole, path)
				http.Error(w, "Forbidden", http.StatusForbidden)
				return
			}

			// Add user to context for downstream handlers
			ctx := context.WithValue(r.Context(), "user", user)
			r = r.WithContext(ctx)
		}

		// Layer 5: Security headers
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("X-Frame-Options", "DENY")
		w.Header().Set("Content-Security-Policy", "default-src 'self'")

		// Request passed all security checks
		sm.logger.Printf("ALLOWED: %s %s from %s", method, path, remoteIP)
		next(w, r)
	}
}

func (sm *SecurityMiddleware) authenticateRequest(r *http.Request) (*User, error) {
	token := r.Header.Get("Authorization")
	if token == "" {
		return nil, ErrMissingToken
	}

	// Remove "Bearer " prefix if present
	token = strings.TrimPrefix(token, "Bearer ")
	return sm.authService.ValidateAndGetUser(token)
}

func isMethodAllowed(method string, allowed []string) bool {
	for _, m := range allowed {
		if strings.EqualFold(method, m) {
			return true
		}
	}
	return false
}

func getClientIP(r *http.Request) string {
	// Check X-Forwarded-For for proxied requests
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		ips := strings.Split(xff, ",")
		return strings.TrimSpace(ips[0])
	}
	return r.RemoteAddr
}

func main() {
	authService := NewAuthService()
	secMiddleware := NewSecurityMiddleware(authService)

	// All routes wrapped with security middleware
	http.HandleFunc("/admin/user/delete", secMiddleware.Wrap(deleteUserHandler))
	http.HandleFunc("/admin/user/list", secMiddleware.Wrap(listUsersHandler))
	http.HandleFunc("/api/health", secMiddleware.Wrap(healthHandler))

	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

