```php
<?php
class MethodAwareRateLimiter {
    private $redis;

    // Different limits for different methods
    private array $limits = [
        'GET' => ['requests' => 1000, 'window' => 3600],
        'POST' => ['requests' => 100, 'window' => 3600],
        'DELETE' => ['requests' => 50, 'window' => 3600],
    ];

    public function checkLimit(string $ip, string $method): bool {
        $method = strtoupper($method);
        $limit = $this->limits[$method] ?? $this->limits['GET'];

        $key = "rate_limit:{$method}:{$ip}";
        $current = $this->redis->incr($key);

        if ($current === 1) {
            $this->redis->expire($key, $limit['window']);
        }

        return $current <= $limit['requests'];
    }
}
