                var user = context.HttpContext.User;
                if (!user.IsInRole("Admin"))
                {
                    context.Result = new ForbidResult();
                    return;
                }
            }
            // GET, PUT, PATCH, HEAD, OPTIONS, custom verbs bypass auth!
        }
    }

