using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Filters;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using System;
using System.Linq;
using System.Threading.Tasks;

namespace MyApp.Security
{
    // Global HTTP Method Security Middleware
    public class HttpMethodSecurityMiddleware
    {
        private readonly RequestDelegate _next;
        private readonly ILogger<HttpMethodSecurityMiddleware> _logger;

        // Strict allowlist of HTTP methods
        private static readonly string[] AllowedMethods = 
            { "GET", "POST", "PUT", "DELETE", "PATCH", "OPTIONS", "HEAD" };

        // Methods that should never modify state
        private static readonly string[] SafeMethods = { "GET", "HEAD", "OPTIONS" };

        public HttpMethodSecurityMiddleware(
            RequestDelegate next,
            ILogger<HttpMethodSecurityMiddleware> logger)
        {
            _next = next;
            _logger = logger;
        }

        public async Task InvokeAsync(HttpContext context)
        {
            var method = context.Request.Method.ToUpperInvariant();
            var path = context.Request.Path;
            var origin = context.Request.Headers["Origin"].FirstOrDefault();

            // DEFENSE 1: Block unknown HTTP methods globally
            if (!AllowedMethods.Contains(method))
            {
                _logger.LogWarning(
                    "Blocked unknown HTTP method: {Method} from {IP} to {Path}",
                    method,
                    context.Connection.RemoteIpAddress,
                    path);

                context.Response.StatusCode = 405;
                context.Response.Headers["Allow"] = string.Join(", ", AllowedMethods);
                await context.Response.WriteAsync("Method Not Allowed");
                return;
            }

            // DEFENSE 2: Handle OPTIONS preflight securely
            if (method == "OPTIONS")
            {
                // Let CORS middleware handle valid preflight requests
                // But log for monitoring
                _logger.LogDebug(
                    "CORS preflight from origin {Origin} to {Path}",
                    origin ?? "unknown", path);
            }

            // DEFENSE 3: Ensure HEAD doesn't expose more than GET
            if (method == "HEAD")
            {
                // HEAD should behave like GET but return no body
                // Authorization still applies
                _logger.LogDebug("HEAD request to {Path}", path);
            }

            await _next(context);
        }
    }

    // Enhanced authorization filter with verb-aware security
    public class VerbAwareAuthorizationFilter : IAsyncAuthorizationFilter
    {
        private readonly ILogger<VerbAwareAuthorizationFilter> _logger;

        // Methods that require elevated authorization for sensitive endpoints
        private static readonly string[] StateChangingMethods = 
            { "POST", "PUT", "DELETE", "PATCH" };

        public VerbAwareAuthorizationFilter(ILogger<VerbAwareAuthorizationFilter> logger)
        {
            _logger = logger;
        }

        public async Task OnAuthorizationAsync(AuthorizationFilterContext context)
        {
            var method = context.HttpContext.Request.Method.ToUpperInvariant();
            var user = context.HttpContext.User;
            var endpoint = context.HttpContext.GetEndpoint();

            // Skip auth for CORS preflight (handled by CORS middleware)
            if (method == "OPTIONS")
            {
                return;
            }

            // DEFENSE 4: All protected endpoints require authentication
            if (!user.Identity?.IsAuthenticated ?? true)
            {
                _logger.LogWarning(
                    "Unauthenticated {Method} request to {Path}",
                    method, context.HttpContext.Request.Path);
                context.Result = new UnauthorizedResult();
                return;
            }

            // DEFENSE 5: State-changing methods require additional verification
            if (StateChangingMethods.Contains(method))
            {
                // Verify CSRF token for state-changing requests
                var antiforgery = context.HttpContext.RequestServices
                    .GetService<Microsoft.AspNetCore.Antiforgery.IAntiforgery>();

                if (antiforgery != null)
                {
                    try
                    {
                        await antiforgery.ValidateRequestAsync(context.HttpContext);
                    }
                    catch (Exception ex)
                    {
                        _logger.LogWarning(
                            "CSRF validation failed for {Method} {Path}: {Error}",
                            method, context.HttpContext.Request.Path, ex.Message);
                        context.Result = new BadRequestObjectResult("Invalid request token");
                        return;
                    }
                }
            }

            // Check role-based authorization from endpoint metadata
            var authorizeData = endpoint?.Metadata
                .GetOrderedMetadata<Microsoft.AspNetCore.Authorization.IAuthorizeData>();

            if (authorizeData?.Any() == true)
            {
                foreach (var authData in authorizeData)
                {
                    if (!string.IsNullOrEmpty(authData.Roles))
                    {
                        var roles = authData.Roles.Split(',');
                        if (!roles.Any(role => user.IsInRole(role.Trim())))
                        {
                            _logger.LogWarning(
                                "Role check failed for {User}: required {Roles}",
                                user.Identity.Name, authData.Roles);
                            context.Result = new ForbidResult();
                            return;
                        }
                    }
                }
            }
        }
    }

    // Startup configuration
    public static class SecurityConfiguration
    {
        public static void ConfigureSecurityServices(IServiceCollection services)
        {
            // Configure strict CORS policy
            services.AddCors(options =>
            {
                options.AddPolicy("ProductionPolicy", builder =>
                {
                    builder
                        .WithOrigins(
                            "https://app.example.com",
                            "https://admin.example.com")
                        .WithMethods("GET", "POST", "PUT", "DELETE", "PATCH")
                        .WithHeaders(
                            "Authorization",
                            "Content-Type",
                            "X-Requested-With",
                            "X-CSRF-Token")
                        .SetPreflightMaxAge(TimeSpan.FromMinutes(10));
                });
            });

            // Add antiforgery for CSRF protection
            services.AddAntiforgery(options =>
            {
                options.HeaderName = "X-CSRF-Token";
                options.Cookie.SecurePolicy = CookieSecurePolicy.Always;
                options.Cookie.SameSite = SameSiteMode.Strict;
            });

            services.AddScoped<VerbAwareAuthorizationFilter>();
        }

        public static void ConfigureSecurityMiddleware(IApplicationBuilder app)
        {
            // Order matters! Security middleware first
            app.UseMiddleware<HttpMethodSecurityMiddleware>();

            // CORS must come before authentication
            app.UseCors("ProductionPolicy");

            app.UseAuthentication();
            app.UseAuthorization();
        }
    }
}
```

