from flask import Flask, request, jsonify, session, abort, g
from functools import wraps
from enum import Enum
from typing import Dict, Set, Callable
import logging
import time
from datetime import datetime

app = Flask(__name__)
app.secret_key = 'production-secret-from-env'

# Configure structured security logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
security_logger = logging.getLogger('security.access')
audit_logger = logging.getLogger('security.audit')


class Role(Enum):
    GUEST = 0
    USER = 1
    MODERATOR = 2
    ADMIN = 3
    SUPERADMIN = 4


# Centralized permission matrix - single source of truth
PERMISSION_MATRIX: Dict[str, Dict[str, Role]] = {
    '/api/users': {
        'GET': Role.USER,        # Regular users can list
        'POST': Role.ADMIN,      # Only admins can create
        'PUT': Role.ADMIN,       # Only admins can update
        'DELETE': Role.SUPERADMIN  # Only superadmins can delete
    },
    '/api/posts': {
        'GET': Role.GUEST,       # Anyone can read
        'POST': Role.USER,       # Users can create
        'PUT': Role.MODERATOR,   # Moderators can edit
        'DELETE': Role.MODERATOR # Moderators can delete
    },
    '/api/admin/settings': {
        'GET': Role.ADMIN,
        'POST': Role.SUPERADMIN,
        'PUT': Role.SUPERADMIN,
        'DELETE': Role.SUPERADMIN
    }
}

# Strictly allowed HTTP methods - whitelist approach
GLOBALLY_ALLOWED_METHODS: Set[str] = {'GET', 'POST', 'PUT', 'DELETE', 'PATCH'}


def get_user_role() -> Role:
    """Retrieve user role from session with secure default."""
    role_value = session.get('role', 0)
    try:
        return Role(role_value)
    except ValueError:
        security_logger.warning(f"Invalid role value in session: {role_value}")
        return Role.GUEST  # Fail secure to lowest privilege


def method_auth(permissions: Dict[str, Role] = None):
    """
    Decorator for method-specific authorization.

    Usage:
        @method_auth({'GET': Role.USER, 'DELETE': Role.ADMIN})
        def my_endpoint():
            ...
    """
    def decorator(f: Callable):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            request_id = f"{int(time.time())}-{id(request)}"
            g.request_id = request_id

            # LAYER 1: HTTP Method Whitelist
            if request.method not in GLOBALLY_ALLOWED_METHODS:
                security_logger.error(
                    f"[{request_id}] BLOCKED: Unexpected HTTP method '{request.method}' "
                    f"from {request.remote_addr} to {request.path}"
                )
                abort(405)

            # LAYER 2: Endpoint-specific method validation
            endpoint_perms = permissions or PERMISSION_MATRIX.get(request.path, {})

            if request.method not in endpoint_perms:
                security_logger.warning(
                    f"[{request_id}] BLOCKED: Method '{request.method}' not configured "
                    f"for endpoint {request.path} from {request.remote_addr}"
                )
                abort(405)

            # LAYER 3: Role-based authorization
            required_role = endpoint_perms[request.method]
            user_role = get_user_role()
            user_id = session.get('user_id', 'anonymous')

            if user_role.value < required_role.value:
                security_logger.warning(
                    f"[{request_id}] DENIED: User {user_id} (role={user_role.name}) "
                    f"attempted {request.method} {request.path} "
                    f"(requires {required_role.name}) from {request.remote_addr}"
                )
                return jsonify({
                    'error': 'Insufficient permissions',
                    'required_role': required_role.name,
                    'request_id': request_id
                }), 403

            # LAYER 4: Audit successful access
            audit_logger.info(
                f"[{request_id}] GRANTED: User {user_id} (role={user_role.name}) "
                f"{request.method} {request.path} from {request.remote_addr}"
            )

            return f(*args, **kwargs)
        return decorated_function
    return decorator


@app.before_request
def enforce_global_method_whitelist():
    """Global safety net - blocks unexpected methods before routing."""
    if request.method not in GLOBALLY_ALLOWED_METHODS:
        security_logger.critical(
            f"GLOBAL BLOCK: Unexpected method '{request.method}' "
            f"from {request.remote_addr} to {request.path}"
        )
        abort(405)


@app.route('/api/users', methods=['GET', 'POST', 'PUT', 'DELETE'])
@method_auth({
    'GET': Role.USER,
    'POST': Role.ADMIN,
    'PUT': Role.ADMIN,
    'DELETE': Role.SUPERADMIN
})
def users_endpoint():
    """User management endpoint with method-specific authorization."""
    if request.method == 'GET':
        return jsonify({'users': [{'id': 1, 'name': 'Alice'}]})
    elif request.method == 'POST':
        return jsonify({'created': True, 'request_id': g.request_id}), 201
    elif request.method == 'PUT':
        return jsonify({'updated': True, 'request_id': g.request_id})
    elif request.method == 'DELETE':
        return jsonify({'deleted': True, 'request_id': g.request_id})


@app.route('/api/admin/settings', methods=['GET', 'POST', 'PUT', 'DELETE'])
