  // Check authorization for ALL HTTP methods
  if (!req.user) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  if (req.user.role !== 'admin') {
    console.warn(`Unauthorized admin access attempt: user=${req.user.id}, method=${req.method}, path=${req.path}`);
    return res.status(403).json({ error: 'Admin access required' });
  }

  next();
}

// Apply admin check to ALL requests on admin routes
