**Key Security Controls**:
- Authorization middleware checks ALL HTTP methods unconditionally
- Use explicit route handlers (get, post, delete, patch) instead of app.all()
- Catch-all route at the end explicitly rejects unexpected HTTP verbs
- Audit logging captures unauthorized access attempts with context

For production systems with complex RBAC requirements, you need a comprehensive authorization framework that handles method-specific permissions with multiple defense layers.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const winston = require('winston');

const app = express();

// Security headers
app.use(helmet());

// Structured logging for security events
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Permission definitions: resource -> method -> required permissions
const PERMISSIONS = {
  '/api/users': {
    GET: ['users:read'],
    POST: ['users:create', 'admin'],
    PUT: ['users:update'],
    PATCH: ['users:update'],
    DELETE: ['users:delete', 'admin'],
    // Explicitly define allowed methods
    _allowedMethods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE']
  },
  '/api/admin/settings': {
    GET: ['admin', 'settings:read'],
    PUT: ['admin', 'settings:write'],
    PATCH: ['admin', 'settings:write'],
    _allowedMethods: ['GET', 'PUT', 'PATCH']
  }
};

// Normalize HTTP method (handle method override attacks)
function normalizeMethod(req) {
  // Block X-HTTP-Method-Override in production
  if (req.headers['x-http-method-override']) {
    securityLogger.warn({
      event: 'method_override_attempt',
      ip: req.ip,
      originalMethod: req.method,
      overrideAttempt: req.headers['x-http-method-override'],
      userId: req.user?.id
    });
    return null; // Signal invalid request
  }
  return req.method.toUpperCase();
}

// Find matching permission rule for a path
function getPermissionRule(path) {
  // Exact match first
  if (PERMISSIONS[path]) {
    return PERMISSIONS[path];
  }
  // Then check pattern matches (e.g., /api/users/:id)
  for (const [pattern, rules] of Object.entries(PERMISSIONS)) {
    const regex = new RegExp('^' + pattern.replace(/:\w+/g, '[^/]+') + '(?:/[^/]+)?$');
    if (regex.test(path)) {
      return rules;
    }
  }
  return null;
}

// Check if user has required permissions
function hasPermissions(user, requiredPerms) {
  if (!user || !user.permissions) return false;
  return requiredPerms.every(perm => user.permissions.includes(perm));
}

// Comprehensive authorization middleware
function authorize(req, res, next) {
  const method = normalizeMethod(req);

  // Block method override attacks
  if (method === null) {
    return res.status(400).json({ error: 'Invalid request method' });
  }

  const rule = getPermissionRule(req.path);

  // No rule means endpoint doesn't exist or isn't protected
  if (!rule) {
    return next();
  }

  // CRITICAL: Check if method is explicitly allowed
  if (!rule._allowedMethods.includes(method)) {
    securityLogger.warn({
      event: 'disallowed_method',
      ip: req.ip,
      method: method,
      path: req.path,
      userId: req.user?.id,
      timestamp: new Date().toISOString()
    });
    res.set('Allow', rule._allowedMethods.join(', '));
    return res.status(405).json({ 
      error: 'Method not allowed',
      allowed: rule._allowedMethods 
    });
  }

  // Check authentication
  if (!req.user) {
    securityLogger.info({
      event: 'unauthenticated_access',
      ip: req.ip,
      method: method,
      path: req.path
    });
    return res.status(401).json({ error: 'Authentication required' });
  }

  // Check authorization for this method
  const requiredPerms = rule[method];
  if (!requiredPerms) {
    // Method exists but no permissions defined - fail secure
    securityLogger.error({
      event: 'missing_permission_config',
      method: method,
      path: req.path
    });
    return res.status(500).json({ error: 'Configuration error' });
  }

  if (!hasPermissions(req.user, requiredPerms)) {
    securityLogger.warn({
      event: 'authorization_failed',
      ip: req.ip,
      userId: req.user.id,
      method: method,
      path: req.path,
      required: requiredPerms,
      userPerms: req.user.permissions,
      timestamp: new Date().toISOString()
    });
    return res.status(403).json({ error: 'Insufficient permissions' });
  }

  // Log successful authorization for sensitive operations
  if (requiredPerms.includes('admin')) {
    securityLogger.info({
      event: 'admin_action',
      userId: req.user.id,
      method: method,
      path: req.path,
      timestamp: new Date().toISOString()
    });
  }

  next();
}

// Rate limiting per method sensitivity
const adminLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 50,
  message: { error: 'Too many admin requests' }
});

const writeLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many write requests' }
});

// Apply middleware stack
app.use(express.json());
app.use('/api/admin', adminLimiter);
app.use('/api', (req, res, next) => {
  if (['POST', 'PUT', 'PATCH', 'DELETE'].includes(req.method)) {
    return writeLimiter(req, res, next);
  }
  next();
});
app.use(authorize);

// Define routes with explicit methods only
const userRouter = express.Router();

userRouter.get('/', (req, res) => {
  res.json(getUsers());
});

userRouter.get('/:id', (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (isNaN(id)) return res.status(400).json({ error: 'Invalid ID' });
  res.json(getUserById(id));
});

userRouter.post('/', (req, res) => {
  const user = createUser(req.body);
  res.status(201).json(user);
});

userRouter.delete('/:id', (req, res) => {
  const id = parseInt(req.params.id, 10);
  if (isNaN(id)) return res.status(400).json({ error: 'Invalid ID' });
  deleteUser(id);
  res.status(204).send();
});

// CRITICAL: Catch-all for undefined methods
userRouter.all('*', (req, res) => {
  res.status(405).json({ error: 'Method not allowed' });
});

app.use('/api/users', userRouter);

// Global error handler - don't leak details
app.use((err, req, res, next) => {
  securityLogger.error({
    event: 'unhandled_error',
    error: err.message,
    stack: err.stack,
    path: req.path,
    method: req.method
  });
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Method Normalization & Override Prevention**:
```javascript
// Block X-HTTP-Method-Override header exploitation
if (req.headers['x-http-method-override']) {
  securityLogger.warn({ event: 'method_override_attempt', ... });
  return null; // Reject request
}
```

2. **Explicit Method Whitelisting**:
```javascript
// Only explicitly listed methods are allowed
if (!rule._allowedMethods.includes(method)) {
  res.set('Allow', rule._allowedMethods.join(', '));
  return res.status(405).json({ error: 'Method not allowed' });
}
```

3. **Fail-Secure Permission Checks**:
```javascript
// If permissions aren't configured, deny by default
if (!requiredPerms) {
  securityLogger.error({ event: 'missing_permission_config', ... });
  return res.status(500).json({ error: 'Configuration error' });
}
```

**Additional Protections**:
- Security headers via Helmet prevent additional attack vectors
- Rate limiting varies by operation sensitivity (admin vs regular)
- Comprehensive audit logging with structured data for SIEM integration
- Catch-all route handlers reject unexpected methods at route level
- Environment-aware configuration for development vs production
- Input validation at every endpoint to prevent injection attacks
- No information leakage in error responses to prevent enumeration

