// HttpMethodValidationFilter.java - Defense in depth filter
package com.example.security;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.util.Set;

public class HttpMethodValidationFilter extends OncePerRequestFilter {

    private static final Logger logger = LoggerFactory.getLogger(HttpMethodValidationFilter.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    // SECURE: Whitelist of allowed HTTP methods
    private static final Set<String> ALLOWED_METHODS = Set.of(
        "GET", "POST", "PUT", "DELETE", "PATCH"
    );

    // Methods that should trigger security alerts
    private static final Set<String> SUSPICIOUS_METHODS = Set.of(
        "TRACE", "TRACK", "CONNECT", "DEBUG", "PROPFIND", "PROPPATCH",
        "MKCOL", "COPY", "MOVE", "LOCK", "UNLOCK", "VERSION-CONTROL"
    );

    @Override
    protected void doFilterInternal(HttpServletRequest request, 
                                    HttpServletResponse response, 
                                    FilterChain filterChain) 
            throws ServletException, IOException {

        String method = request.getMethod().toUpperCase();
        String uri = request.getRequestURI();
        String remoteAddr = getClientIP(request);
        String userAgent = request.getHeader("User-Agent");

        // Check for HTTP method override headers (potential bypass attempt)
        String methodOverride = request.getHeader("X-HTTP-Method-Override");
        if (methodOverride == null) {
            methodOverride = request.getHeader("X-HTTP-Method");
        }
        if (methodOverride == null) {
            methodOverride = request.getHeader("X-Method-Override");
        }

        if (methodOverride != null) {
            securityLogger.warn("HTTP method override attempt detected - " +
                "Original: {}, Override: {}, IP: {}, URI: {}, UA: {}",
                method, methodOverride, remoteAddr, uri, userAgent);
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, 
                             "Method override not allowed");
            return;
        }

        // Validate HTTP method
        if (!ALLOWED_METHODS.contains(method)) {
            if (SUSPICIOUS_METHODS.contains(method)) {
                // High-severity alert for known attack methods
                securityLogger.error("HTTP verb tampering ATTACK detected - " +
                    "Method: {}, IP: {}, URI: {}, UA: {}",
                    method, remoteAddr, uri, userAgent);
            } else {
                // Custom/unknown method
                securityLogger.warn("Unknown HTTP method rejected - " +
                    "Method: {}, IP: {}, URI: {}",
                    method, remoteAddr, uri);
            }

            response.setHeader("Allow", String.join(", ", ALLOWED_METHODS));
            response.sendError(HttpServletResponse.SC_METHOD_NOT_ALLOWED);
            return;
        }

        filterChain.doFilter(request, response);
    }

    private String getClientIP(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}
